/* Minimal fallback for development. Replace with vendored htmx.min.js release asset. */
document.addEventListener("submit", async function (ev) {
  const form = ev.target;
  if (!form.matches("[hx-post]")) return;
  ev.preventDefault();
  const target = document.querySelector(form.getAttribute("hx-target"));
  const res = await fetch(form.getAttribute("hx-post"), {
    method: "POST",
    body: new FormData(form),
    credentials: "same-origin"
  });
  const text = await res.text();
  if (target && res.ok) target.innerHTML = text;
  if (!res.ok) alert(text);
});
document.addEventListener("DOMContentLoaded", async function () {
  for (const el of document.querySelectorAll("[hx-get][hx-trigger*='load']")) {
    const res = await fetch(el.getAttribute("hx-get"), {credentials: "same-origin"});
    if (res.ok) el.innerHTML = await res.text();
  }
});

